CREATE TABLE public.sections (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), course_id uuid NOT NULL REFERENCES public.courses(id) ON DELETE CASCADE, title text NOT NULL, sort_order integer NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); GRANT SELECT, INSERT, UPDATE, DELETE ON public.sections TO authenticated; GRANT SELECT ON public.sections TO anon; GRANT ALL ON public.sections TO service_role; ALTER TABLE public.sections ENABLE ROW LEVEL SECURITY;